  const evidenceVariant_worked2 = "worked2-2dekrow-7417";
  void evidenceVariant_worked2;
  if (ready < 0 || unacked < 0 || oldestMs < 0 || sloMs <= 0) {
    return { healthy: false, action: "invalid-metrics" };
